const data = $json["Time Series (Daily)"];

const dates = Object.keys(data).sort((a, b) => b.localeCompare(a));

const latestDate = dates[0];
const previousDate = dates[1];

const latest = data[latestDate];
const previous = data[previousDate];

const latestClose = parseFloat(latest["4. close"]);
const previousClose = parseFloat(previous["4. close"]);

const changePercent =
  ((latestClose - previousClose) / previousClose) * 100;

return [
  {
    symbol: $json["Meta Data"]["2. Symbol"],
    date: latestDate,
    close: latestClose,
    previousClose,
    changePercent: changePercent.toFixed(2),
    trend:
      changePercent > 0
        ? "Bullish"
        : changePercent < 0
        ? "Bearish"
        : "Neutral"
  }
];

const now = new Date();
const last24h = 24 * 60 * 60 * 1000;

return items
  .map(item => {
    const published = new Date(item.json.pubDate);
    return {
      headline: item.json.title,
      summary: item.json.contentSnippet || "",
      source: "Google News",
      publishedAt: published,
      ageHours: Math.round((now - published) / (1000 * 60 * 60))
    };
  })
  .filter(news => now - news.publishedAt <= last24h);

const rawText =
  $json.output?.[0]?.content?.[0]?.text || "";

// Normalize text to reduce markdown edge cases
const text = rawText
  .replace(/\r/g, "")
  .replace(/[ ]{2,}\n/g, "\n")
  .trim();

// Clean bullet prefixes like "-", "•", extra spaces
function cleanBullets(section) {
  return section
    .split("\n")
    .map(line =>
      line
        .replace(/^[-•]\s*/g, "") // remove leading dash or bullet
        .trim()
    )
    .filter(Boolean)
    .join("\n");
}

// Generic extractor that supports:
// ### Title
// **Title**
function extractSection(title, body) {
  const patterns = [
    // ### Market Summary
    new RegExp(
      `###\\s*${title}\\s*\\n([\\s\\S]*?)(?=\\n###\\s*|\\n\\*\\*|$)`,
      "i"
    ),
    // **Market Summary**
    new RegExp(
      `\\*\\*${title}\\*\\*\\s*\\n([\\s\\S]*?)(?=\\n\\*\\*|\\n###\\s*|$)`,
      "i"
    )
  ];

  for (const pattern of patterns) {
    const match = body.match(pattern);
    if (match && match[1]) {
      return cleanBullets(match[1].trim());
    }
  }

  return "";
}

const marketSummary = extractSection("Market Summary", text);
const sentiment = extractSection("Sentiment", text);
const keyDrivers = extractSection("Key Drivers", text);
const risks = extractSection("Risks", text);
const actionableInsight = extractSection("Actionable Insight", text);

return [
  {
    marketSummary,
    sentiment,
    keyDrivers,
    risks,
    actionableInsight,
    fullText: rawText
  }
];

return items.map(item => ({
  platform: "Reddit",
  source: "r/stocks",
  text:
    (item.json.title || "") +
    " " +
    (item.json.contentSnippet || ""),
  publishedAt: item.json.pubDate
}));

return [{
  stock: $items("Normalize Stock Data")[0]?.json,
  news: $items("Normalize Market News").map(i => i.json),
  reddit: $items("Normalize Reddit News").map(i => i.json)
}];

